INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('tech_cloud_architect', 'Technology', 'Cloud Architect', 'I am writing to express my enthusiastic interest in the Cloud Architect position at {company_name}. With {years} years managing complex military IT infrastructure including classified cloud environments, I bring hands-on experience in designing, deploying, and securing enterprise-scale cloud solutions.', 'In my military career, I architected and migrated mission-critical systems to cloud environments supporting {user_count}+ users across multiple security domains. I led teams of {team_size} in implementing Infrastructure as Code, containerization, and CI/CD pipelines. I hold AWS/Azure certifications and have direct experience with FedRAMP authorization processes, multi-region deployments, and zero-trust architectures.', 'My military background has instilled a security-first mindset that is invaluable in cloud architecture. I understand compliance frameworks (NIST, FISMA, FedRAMP) at a deep level and can design architectures that meet both performance and security requirements. I am passionate about automation and infrastructure optimization.', 'I would welcome the opportunity to discuss how my cloud and infrastructure experience can support {company_name}''s technology goals. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Technology Cloud Architect roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('tech_product_manager', 'Technology', 'Product Manager', 'I am excited to apply for the Product Manager position at {company_name}. My {years} years of military service have given me exceptional skills in requirements gathering, stakeholder management, and delivering complex capabilities under tight constraints — core product management competencies.', 'As a military officer, I managed the development and fielding of technology capabilities that served thousands of end users. I wrote requirements documents, coordinated with development teams, conducted user acceptance testing, and iterated based on operational feedback. My experience translating mission needs into technical requirements mirrors the product manager''s role of bridging business and engineering.', 'I bring a user-centric approach honed by working directly with the people who used the systems I helped develop. I am data-driven, comfortable with ambiguity, and skilled at prioritization — deciding what to build first when resources are limited is something I did every day in the military.', 'I am confident my background in capability development and stakeholder coordination makes me a strong product management candidate. I look forward to discussing how I can contribute to {company_name}.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Technology Product Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('healthcare_nurse_manager', 'Healthcare', 'Nurse Manager', 'I am applying for the Nurse Manager position at {company_name}. As a military healthcare professional with {years} years of clinical and leadership experience, I bring a unique combination of medical expertise, team management, and operational excellence to patient care leadership.', 'During my military career, I managed clinical units serving {patient_count}+ patients, supervised teams of {team_size} nurses and medics, and maintained compliance with stringent medical regulations. I implemented quality improvement initiatives that reduced medication errors by {metric}% and improved patient satisfaction scores. My experience in high-acuity and austere environments has made me an adaptable and resilient leader.', 'I am passionate about evidence-based practice and creating environments where nurses thrive. My military leadership training emphasizes servant leadership, professional development, and building cohesive teams — values that align with excellence in patient care management.', 'I look forward to discussing how my clinical leadership experience can benefit {company_name}''s nursing team. Thank you for considering my application.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Healthcare Nurse Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('finance_controller', 'Finance', 'Controller', 'I am writing to apply for the Controller position at {company_name}. My {years} years of military financial management experience, including oversight of budgets exceeding ${budget}, has prepared me to deliver the financial leadership and accuracy this role demands.', 'As a military comptroller, I directed all financial operations for a {scope}-person organization, managing appropriated and non-appropriated funds. I led a finance team of {team_size}, prepared financial statements, conducted internal audits, and ensured compliance with federal financial management regulations. My track record includes zero material findings across multiple command inspections.', 'I bring a meticulous approach to financial management developed in an environment where accountability is non-negotiable. My ability to implement internal controls, analyze financial data, and present complex information to non-financial stakeholders will add immediate value to {company_name}.', 'I would appreciate the opportunity to discuss how my financial management expertise aligns with {company_name}''s needs. Thank you for your time and consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Finance Controller roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('govt_cyber_policy', 'Government', 'Cybersecurity Policy Analyst', 'I am applying for the Cybersecurity Policy Analyst position at {company_name}. With {years} years of military cybersecurity experience and deep knowledge of federal security frameworks, I am well-positioned to contribute to your organization''s cyber policy and governance mission.', 'In my military career, I developed and implemented cybersecurity policies aligned with NIST, FISMA, and DoD frameworks. I authored security plans, managed Authority to Operate (ATO) packages, and conducted risk assessments for systems processing classified information. My experience includes briefing senior leaders on cyber threats and recommending policy changes.', 'I understand the intersection of technology, policy, and operations that defines effective cybersecurity governance. My ability to translate technical risks into policy language and communicate across all organizational levels makes me effective at driving security improvements.', 'I am eager to bring my cybersecurity policy expertise to {company_name}. I look forward to discussing this opportunity.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Government Cybersecurity Policy Analyst roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('generic_entry_level', 'General', 'Entry Level', 'I am writing to apply for the {role_type} position at {company_name}. As a recently separated military veteran with {years} years of dedicated service, I am eager to launch my civilian career in an environment that values discipline, teamwork, and a strong work ethic.', 'While my military title may not directly match this role, the skills I developed are highly transferable. I am experienced in team collaboration, meeting strict deadlines, following detailed procedures, and maintaining high standards of quality. I learned to operate sophisticated equipment, manage multiple priorities, and adapt quickly to changing situations.', 'What I may lack in specific industry experience, I more than compensate for with my eagerness to learn, proven reliability, and ability to perform under pressure. Military service taught me that excellence is a habit, not an event, and I bring that mindset to every task I undertake.', 'I would appreciate the opportunity to discuss how my military-honed skills and strong work ethic can contribute to {company_name}. Thank you for considering a veteran for this role.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for General Entry Level roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('generic_mid_career', 'General', 'Mid-Career Professional', 'I am excited to apply for the {role_type} position at {company_name}. With {years} years of military leadership experience managing teams, budgets, and complex operations, I am ready to bring proven management capabilities to your organization.', 'Throughout my military career, I led teams of {team_size}+ personnel and managed operations with budgets exceeding ${budget}. I have been responsible for training, performance management, strategic planning, and operational execution. My experience spans multiple assignments requiring rapid adaptation to new environments, technologies, and challenges.', 'Military leaders are some of the most tested managers in the world. We are responsible for our people 24/7, must make decisions with incomplete information, and are held to the highest standards of accountability. I bring these leadership competencies — plus a deep commitment to professional growth — to every role I take on.', 'I am confident that my leadership experience and management skills make me a strong candidate for this role. I welcome the opportunity to discuss how I can contribute to {company_name}''s success.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for General Mid-Career Professional roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('generic_senior_leader', 'General', 'Senior Executive', 'I am writing to express my interest in the {role_type} position at {company_name}. As a senior military leader with {years}+ years of executive experience directing large organizations, managing multi-million dollar budgets, and driving strategic transformation, I bring the leadership depth this role requires.', 'In my most recent assignment, I led an organization of {team_size}+ personnel with an annual budget of ${budget}. I was responsible for strategic planning, organizational performance, talent development, and stakeholder engagement at the highest levels. I routinely briefed general/flag officers and civilian executives, managed complex inter-organizational relationships, and drove change across resistant bureaucracies.', 'Senior military leaders develop a rare combination of strategic vision, operational rigor, and people leadership. I have guided organizations through transformative change, built high-performance cultures, and delivered results in the most challenging environments imaginable. I am eager to apply this executive experience in the private sector.', 'I would welcome the opportunity to discuss how my senior leadership experience can drive {company_name}''s strategic objectives. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for General Senior Executive roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('generic_technical_expert', 'General', 'Technical Specialist', 'I am applying for the {role_type} position at {company_name}. As a military warrant officer / technical specialist with {years} years of deep expertise in {domain}, I bring a rare combination of hands-on technical mastery and leadership ability.', 'Military technical specialists are recognized as subject matter experts in their fields. I have {years}+ years of progressive technical experience including system design, troubleshooting, maintenance, and training. I am certified in {certifications} and have maintained equipment valued at ${value}+ with exceptional availability rates.', 'Unlike purely technical professionals, my military background gives me strong communication, mentoring, and project management skills. I can lead technical teams, explain complex concepts to non-technical stakeholders, and drive continuous improvement. This combination of depth and breadth is what makes military technical experts valuable in civilian roles.', 'I look forward to discussing how my technical expertise and leadership experience can benefit {company_name}. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for General Technical Specialist roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('generic_career_changer', 'General', 'Career Transition', 'I am writing to apply for the {role_type} position at {company_name}. While my military career was in a different field, I have developed transferable skills and a passion for {industry} that make me an excellent candidate for this transition.', 'My military experience taught me core professional competencies that transcend any specific industry: leadership, problem-solving, project management, and the ability to learn quickly in complex environments. I have supplemented my military background with {certifications} and self-directed study in {industry}, preparing me to contribute from day one.', 'Career changers from the military bring a unique perspective and diverse problem-solving approach that can be a competitive advantage for your team. I am not afraid of steep learning curves — my entire military career was defined by rapidly mastering new skills and environments. I am committed to investing the effort needed to excel in this new direction.', 'I appreciate your willingness to consider non-traditional candidates and would welcome the chance to discuss how my transferable skills can benefit {company_name}. Thank you.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for General Career Transition roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('defense_intel_analyst', 'Defense', 'Intelligence Analyst', 'I am applying for the Intelligence Analyst position at {company_name}. With {years} years as a military intelligence professional holding {clearance_level} clearances, I bring the analytical rigor, security awareness, and domain expertise this role demands.', 'In my military intelligence career, I produced all-source analytical products that directly informed senior leader decision-making. I processed intelligence from multiple disciplines (HUMINT, SIGINT, GEOINT, OSINT), conducted link analysis, and briefed findings to flag-level officers. I am proficient with intelligence tools including Palantir, Analyst Notebook, ArcGIS, and standard IC databases.', 'Intelligence analysis requires not just technical skill but the judgment to assess credibility, identify gaps, and communicate uncertainty. My military training developed these critical thinking skills in high-stakes environments where the consequences of analytical errors are severe. I bring this same rigor to every analytical challenge.', 'I look forward to discussing how my intelligence experience can support {company_name}''s analytical mission. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Defense Intelligence Analyst roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('logistics_supply_chain_director', 'Logistics', 'Supply Chain Director', 'I am writing to apply for the Supply Chain Director role at {company_name}. With {years} years of military logistics leadership managing global supply chains valued at ${value}+, I bring the strategic vision and operational expertise to drive your supply chain forward.', 'As a senior military logistics officer, I directed supply chain operations spanning multiple continents, managed vendor relationships, and optimized distribution networks. I led organizations of {team_size}+ logistics professionals, implemented ERP systems, and achieved cost savings of ${savings}+ through process improvement and strategic sourcing initiatives.', 'Military supply chains operate under constraints most commercial organizations never face — austere environments, unpredictable demand, and zero tolerance for stock-outs of critical items. This experience has made me expert at contingency planning, risk mitigation, and building resilient supply chains that perform under any conditions.', 'I am eager to bring my global logistics experience to {company_name}. I look forward to discussing this opportunity in detail.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Logistics Supply Chain Director roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('manufacturing_plant_manager', 'Manufacturing', 'Plant Manager', 'I am excited to apply for the Plant Manager position at {company_name}. With {years} years of military operations and maintenance management experience, I bring a proven track record of leading large teams, optimizing processes, and delivering operational excellence.', 'In my most recent role, I managed a maintenance facility with {team_size}+ technicians responsible for {count}+ pieces of equipment valued at ${value}+. I implemented lean processes that reduced cycle time by {metric}%, improved first-pass quality to {quality}%, and achieved the highest readiness rates in the organization. I am Six Sigma certified and experienced in continuous improvement methodologies.', 'I understand that plant management requires balancing production targets with safety, quality, and cost objectives. My military career was built on exactly this kind of multi-dimensional optimization in environments where failure was not an option. I am ready to bring this disciplined approach to {company_name}''s manufacturing operations.', 'I would welcome the chance to discuss how my operational leadership experience can benefit {company_name}''s manufacturing objectives. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Manufacturing Plant Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('energy_safety_director', 'Energy', 'Safety Director', 'I am applying for the Safety Director position at {company_name}. My {years} years of military safety management experience, including oversight of high-risk operations with zero fatalities, qualifies me to lead your organization''s safety program.', 'As a military safety officer, I managed comprehensive safety programs for organizations of {team_size}+ personnel operating heavy equipment, hazardous materials, and high-voltage electrical systems. I conducted risk assessments, led accident investigations, and implemented preventive measures that reduced incident rates by {metric}%. I hold OSHA certifications and am experienced in regulatory compliance across multiple safety domains.', 'In the military, safety is not just a program — it is a culture. I have built safety cultures from the ground up, transforming organizations from reactive to proactive safety management. I bring this culture-building expertise, combined with technical safety knowledge, to drive continuous improvement in workplace safety.', 'I look forward to discussing how my safety leadership experience can strengthen {company_name}''s safety program. Thank you for your time.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Energy Safety Director roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('nonprofit_executive_director', 'Non-Profit', 'Executive Director', 'I am writing to express my interest in the Executive Director position at {company_name}. My {years} years of military senior leadership experience, combined with a deep commitment to service, make me an ideal candidate to lead your organization''s mission.', 'As a senior military leader, I directed organizations of {team_size}+ personnel with budgets exceeding ${budget}. I developed strategic plans, built partnerships with government and community stakeholders, managed donor relationships (in the form of congressional appropriations), and drove organizational performance. My experience in leading mission-driven organizations translates directly to non-profit leadership.', 'Military veterans understand service, sacrifice, and mission above self — the same values that drive non-profit work. I am passionate about {company_name}''s mission and am ready to bring my strategic leadership, operational management, and stakeholder engagement skills to advance your goals.', 'I would welcome the opportunity to discuss how my leadership experience can serve {company_name}''s mission. Thank you for considering my application.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Non-Profit Executive Director roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('construction_safety_officer', 'Construction', 'Construction Safety Officer', 'I am applying for the Construction Safety Officer position at {company_name}. My {years} years of military experience in construction safety, hazard mitigation, and regulatory compliance make me well-qualified for this role.', 'In my military career, I managed safety programs for construction projects valued at ${value}+, conducting daily site inspections, leading toolbox talks, and ensuring compliance with OSHA standards. I investigated {count} incidents and implemented corrective actions that reduced injuries by {metric}%. I hold OSHA 30-Hour Construction certification and am experienced in fall protection, scaffolding safety, and excavation safety.', 'I believe that every construction injury is preventable. My approach combines rigorous compliance monitoring with proactive safety culture building — engaging workers at every level to take ownership of safety. This philosophy has consistently produced best-in-class safety records.', 'I look forward to discussing how my construction safety expertise can benefit {company_name}. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Construction Construction Safety Officer roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('telecom_network_architect', 'Telecommunications', 'Network Architect', 'I am excited to apply for the Network Architect position at {company_name}. With {years} years of military telecommunications experience designing and deploying networks across diverse and challenging environments, I bring the technical depth and leadership skills this role requires.', 'In my military career, I designed and implemented network architectures supporting {user_count}+ users across multiple classification levels. I have experience with enterprise routing and switching, MPLS, SD-WAN, network segmentation, and satellite communications. I managed network refresh projects valued at ${value}+ and maintained {uptime}% availability across mission-critical systems.', 'Military network architects must design for reliability, security, and scalability simultaneously — often in austere environments with limited bandwidth. This experience has made me exceptional at optimizing network performance within constraints and designing resilient architectures that maintain service under any conditions.', 'I am eager to bring my network architecture experience to {company_name}. I look forward to discussing this opportunity.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Telecommunications Network Architect roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_quality_manager', 'Aerospace', 'Quality Manager', 'I am applying for the Quality Manager position at {company_name}. My {years} years in military aerospace quality assurance, with a proven record of maintaining flight safety and equipment readiness standards, make me an ideal candidate.', 'As a military quality assurance representative, I oversaw maintenance operations for aircraft valued at ${value}+, conducting inspections, managing technical data, and ensuring compliance with airworthiness directives. I led quality teams of {team_size} and implemented inspection programs that achieved {metric}% defect detection rates. I am AS9100 trained and experienced in root cause analysis, FMEA, and statistical process control.', 'In military aviation, quality is not negotiable — it is directly linked to saving lives. I bring this uncompromising commitment to quality, combined with practical experience in aerospace manufacturing and maintenance environments, to drive quality excellence at {company_name}.', 'I would welcome the chance to discuss how my aerospace quality experience can benefit {company_name}. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Aerospace Quality Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('consulting_it_consultant', 'Consulting', 'IT Consultant', 'I am writing to apply for the IT Consultant position at {company_name}. My {years} years of military IT management experience, combined with strong analytical and communication skills, make me well-suited for technology consulting.', 'In the military, I served as an IT advisor to senior leaders, assessing technology needs, recommending solutions, and managing implementations. I have experience in enterprise architecture, cloud migration, cybersecurity, and IT governance. I translated complex technical concepts for non-technical decision-makers and managed vendor relationships worth ${value}+.', 'Consulting requires the ability to rapidly understand new environments, build trust with stakeholders, and deliver actionable recommendations. These are skills I exercised daily in the military, where I frequently deployed to new assignments and had to quickly assess situations, build relationships, and drive results.', 'I am enthusiastic about the opportunity to bring my IT advisory experience to {company_name}''s consulting practice. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Consulting IT Consultant roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('retail_regional_manager', 'Retail', 'Regional Manager', 'I am applying for the Regional Manager position at {company_name}. With {years} years of military leadership experience managing distributed operations across multiple locations, I bring the operational and people management skills needed to drive multi-store performance.', 'As a senior military leader, I managed operations across {count}+ geographically dispersed locations, each with their own teams and operational challenges. I standardized processes, implemented performance metrics, and conducted regular site visits to ensure consistency and quality. My experience in P&L management, talent development, and operational troubleshooting translates directly to multi-unit retail leadership.', 'Regional management requires balancing standardization with local flexibility — exactly what military leaders do when managing units across different installations. I am skilled at setting clear expectations, holding people accountable, and developing leaders at every location to drive independent excellence.', 'I look forward to discussing how my multi-site leadership experience can drive results for {company_name}''s regional operations. Thank you.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Retail Regional Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('education_stem_instructor', 'Education', 'STEM Instructor', 'I am excited to apply for the STEM Instructor position at {company_name}. My {years} years of military technical experience, combined with a passion for teaching and mentoring, make me uniquely qualified to inspire the next generation of STEM professionals.', 'In the military, I worked with advanced technology daily — from communication systems and cybersecurity tools to navigation equipment and data analytics platforms. I also served as an instructor, teaching complex technical subjects to diverse learners and achieving exceptional qualification rates. I can bring real-world technical experience into the classroom to make STEM subjects tangible and engaging.', 'Military instructors are among the most effective educators because we are trained to teach in high-stakes environments where student performance directly impacts mission success. I use multiple instructional methods, adapt to different learning styles, and create inclusive learning environments where every student can succeed.', 'I would love the opportunity to bring my technical expertise and teaching skills to {company_name}''s STEM program. Thank you for considering my application.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","team_size":"Number of personnel led","clearance_level":"Security clearance level","budget":"Budget amount managed","value":"Asset value managed","metric":"Key performance metric","certifications":"Relevant certifications","industry":"Target industry"}'::jsonb, 'Military-to-civilian cover letter template for Education STEM Instructor roles') ON CONFLICT DO NOTHING;
